//
// CompanyService service processor
//

pub trait CompanyServiceSyncHandler {
  fn handle_get_by_name(&self, industry_id: i32, name: String) -> thrift::Result<Company>;
  fn handle_get_company_services(&self, company_id: i32) -> thrift::Result<Vec<String>>;
  fn handle_get_company_social_network_links(&self, company_id: i32) -> thrift::Result<Vec<SocialNetworkLink>>;
  fn handle_get_company_info(&self, company_id: i32) -> thrift::Result<String>;
  fn handle_users_in_company(&self, company_id: i32) -> thrift::Result<Vec<String>>;
  fn handle_queue_company_history_pull(&self, company_id: i32) -> thrift::Result<()>;
  fn handle_get_by_id(&self, company_id: i32) -> thrift::Result<Company>;
  fn handle_update(&self, company_id: i32, data: CompanyUpdate) -> thrift::Result<()>;
  fn handle_get_display_options(&self, company_id: i32) -> thrift::Result<DisplayOptions>;
  fn handle_set_display_options(&self, company_id: i32, data: DisplayOptions) -> thrift::Result<()>;
  fn handle_get_company_oem_setting(&self, company_id: i32, oem_api_id: i32) -> thrift::Result<OEMInformation>;
  fn handle_enable_company_o_e_m_setting(&self, company_id: i32, oem_api_id: i32, external_id: String) -> thrift::Result<()>;
  fn handle_disable_company_o_e_m_setting(&self, company_id: i32, oem_api_id: i32) -> thrift::Result<()>;
  fn handle_get_company_o_e_m_settings(&self, company_id: i32) -> thrift::Result<Vec<OEMInformation>>;
  fn handle_get_company_o_e_ms(&self, company_id: i32) -> thrift::Result<Vec<OEMInformation>>;
  fn handle_get_notification_message(&self, company_id: i32, promise_type: i32, promise_region: i32) -> thrift::Result<NotificationMessage>;
  fn handle_set_notification_message(&self, notification_message: NotificationMessage) -> thrift::Result<()>;
  fn handle_get_c_d_k_make_model_mapping(&self, company_id: i32) -> thrift::Result<Vec<CDKMakeMap>>;
  fn handle_set_c_d_k_make_model_mapping(&self, company_id: i32, make_model_mapping: Vec<CDKMakeMap>) -> thrift::Result<()>;
  fn handle_get_mfr_code_mapping(&self, company_id: i32) -> thrift::Result<Vec<MfrCodeMap>>;
  fn handle_set_mfr_code_mapping(&self, company_id: i32, mfrcode_mapping: Vec<MfrCodeMap>) -> thrift::Result<()>;
  fn handle_get_price_codes(&self, company_id: i32) -> thrift::Result<Vec<Box<PriceCode>>>;
  fn handle_get_dispatch_codes(&self, company_id: i32) -> thrift::Result<Vec<String>>;
  fn handle_get_part_price_options(&self, company_id: i32) -> thrift::Result<Vec<DMSPartPriceOption>>;
}

pub struct CompanyServiceSyncProcessor<H: CompanyServiceSyncHandler> {
  handler: H,
}

