//
// PromiseService service processor
//

pub trait PromiseServiceSyncHandler {
  fn handle_get_by_id(&self, industry_id: i32, promise_id: i32) -> thrift::Result<Promise>;
  fn handle_get_history(&self, promise_id: i32) -> thrift::Result<Vec<PromiseHistory>>;
  fn handle_validate(&self, industry_id: i32, promise: Promise) -> thrift::Result<BTreeMap<String, String>>;
  fn handle_save(&self, industry_id: i32, promise: Promise, time_zone: String, from_api: bool, from_user_id: i32, from_user_fullname: String) -> thrift::Result<i32>;
  fn handle_delete_promise(&self, industry_id: i32, promise: Promise, queue: bool) -> thrift::Result<()>;
  fn handle_cancel(&self, promise_id: i32) -> thrift::Result<bool>;
  fn handle_uncancel(&self, promise_id: i32) -> thrift::Result<bool>;
  fn handle_queue(&self, industry_id: i32, promise: Promise) -> thrift::Result<()>;
  fn handle_queue_internal_promise(&self, promise: Promise) -> thrift::Result<BTreeMap<String, String>>;
  fn handle_get_tokens(&self, promise_id: i32) -> thrift::Result<BTreeMap<String, String>>;
  fn handle_replace_tokens(&self, promise_id: i32, message: String, extra_params: BTreeMap<String, String>) -> thrift::Result<String>;
  fn handle_get_udp_payment_disclosure(&self, promise_id: i32) -> thrift::Result<String>;
  fn handle_get_promise_companies(&self, login_id: i32, insurance_company_id: i32, campaign_id: i32, filters: BTreeSet<String>, states: BTreeSet<String>, search: String, row_start: i32, rows_per_page: i32, search_field: PromiseSearchFields, login_filters: Vec<i32>) -> thrift::Result<PromiseCompanies>;
  fn handle_get_promise_users(&self, login_id: i32, company_id: Vec<i32>, insurance_company_id: i32, campaign_id: i32, filters: BTreeSet<String>, search: String, search_field: PromiseSearchFields, login_filters: Vec<i32>) -> thrift::Result<Vec<PromiseUser>>;
  fn handle_get_promise_users_from_companies(&self, login_id: i32, company_ids: Vec<i32>, insurance_company_id: i32, campaign_id: i32, filters: BTreeSet<String>, search: String, search_field: PromiseSearchFields, login_filters: Vec<i32>) -> thrift::Result<Vec<PromiseUser>>;
  fn handle_get_promises(&self, login_id: i32, user_id: Vec<i32>, technician_id: Vec<i32>, production_status: Vec<String>, insurance_company_id: i32, campaign_id: i32, filters: BTreeSet<String>, search: String, search_field: PromiseSearchFields, sort_field: String, sort_descending: bool, row_start: i32, rows_per_page: i32) -> thrift::Result<PromisePromises>;
  fn handle_get_promises_from_users(&self, login_id: i32, user_ids: Vec<i32>, insurance_company_id: i32, campaign_id: i32, filters: BTreeSet<String>, search: String, search_field: PromiseSearchFields, sort_field: String, sort_descending: bool, row_start: i32, rows_per_page: i32) -> thrift::Result<PromisePromises>;
  fn handle_log_event(&self, promise_id: i32, description: String, prevent_dups: bool, dup_minutes_apart: i32, double_opt_in_reply_flag: i32, meta_data: String) -> thrift::Result<i32>;
  fn handle_send_customer_message(&self, promise_id: i32, transcript: Box<Transcript>, subject: String, body: String, html_subject: String, html_body: String, attachments: Vec<Attachment>, force: bool) -> thrift::Result<bool>;
  fn handle_update_customer(&self, promise_id: i32, progress_region_id: i32, extra_log_entry: String, extra_params: BTreeMap<String, String>) -> thrift::Result<bool>;
  fn handle_promise_user_access(&self, promise_id: i32, login_id: i32) -> thrift::Result<bool>;
  fn handle_stop(&self, promise_id: i32, method: i32, trancsript_id: i32, reason: String, send_confirmation: bool) -> thrift::Result<()>;
  fn handle_add_social_link_click(&self, promise_id: i32, url_type: String) -> thrift::Result<()>;
  fn handle_social_link_clicked(&self, promise_id: i32, url_type: String) -> thrift::Result<bool>;
  fn handle_import_repair_order(&self, login_id: i32, external_job_id: String) -> thrift::Result<i32>;
  fn handle_get_unread_status(&self, login_id: i32) -> thrift::Result<bool>;
  fn handle_mark_as_read(&self, promise_id: i32, login_id: i32) -> thrift::Result<bool>;
  fn handle_lock_a_p_i(&self, promise_id: i32, login_id: i32, message: String) -> thrift::Result<bool>;
  fn handle_is_a_p_i_locked(&self, promise_id: i32, login_id: i32, message: String) -> thrift::Result<bool>;
  fn handle_unlock_a_p_i(&self, promise_id: i32, login_id: i32, subject: String) -> thrift::Result<bool>;
  fn handle_get_by_unique_identifier(&self, unique_id: String, login_id: i32) -> thrift::Result<i32>;
  fn handle_get_by_claim_number(&self, claim_number: String, login_id: i32) -> thrift::Result<i32>;
}

