//
// OEMService service processor
//

pub trait OEMServiceSyncHandler {
  fn handle_get_vehicle_warranty(&self, company_id: String, vin: String) -> thrift::Result<Vec<VehicleWarranty>>;
  fn handle_push_vehicle_mobile_lane_checkin(&self, company_id: String, vehicle_mobile_lane_checkin: VehicleMobileLaneCheckin) -> thrift::Result<VehicleMobileLaneCheckin>;
  fn handle_push_vehicle_mpi(&self, company_id: String, vehicle_mpi: Vec<Box<Issue>>, promise_id: i32, vehicle_id: i32) -> thrift::Result<String>;
  fn handle_get_national_service_history(&self, company_id: String, vin: String) -> thrift::Result<Vec<VehicleHistory>>;
  fn handle_get_special_service_campaign(&self, company_id: String, vin: String) -> thrift::Result<Box<VehicleRecallResponse>>;
  fn handle_get_vehicle_details(&self, company_id: String, vin: String) -> thrift::Result<Vehicle>;
  fn handle_get_vehicle_health_status(&self, company_id: String, vehicle_id: i32) -> thrift::Result<VehicleHealthStatus>;
  fn handle_push_appointments(&self, company_id: i32, appointments: OEMAppointmentData) -> thrift::Result<OEMResponse>;
  fn handle_search_vehicle_parts(&self, company_id: i32, partial_part_number: String, partial_part_description: String) -> thrift::Result<Vec<VehiclePart>>;
  fn handle_search_opcodes(&self, company_id: i32, partial_opcode: String) -> thrift::Result<Vec<Service>>;
  fn handle_search_opcodes_by_make(&self, company_id: i32, vehicle_make: String, partial_opcode: String) -> thrift::Result<Vec<Service>>;
  fn handle_get_special_service_campaign_by_make(&self, company_id: String, vin: String, vehicle_make: String) -> thrift::Result<Box<VehicleRecallResponse>>;
  fn handle_get_protection_products(&self, company_id: String, vin: String) -> thrift::Result<Vec<Box<ProtectionProduct>>>;
  fn handle_get_customer_associated_vehicles(&self, company_id: String, customer_id: String) -> thrift::Result<Vec<OEMAssociatedVehicle>>;
  fn handle_get_tire_recommendations(&self, company_id: String, location_code: String, jsonified_param: String) -> thrift::Result<Vec<BTreeMap<String, String>>>;
  fn handle_create_consumer_lead(&self, company_id: String, location_code: String, jsonified_request_body: String) -> thrift::Result<String>;
  fn handle_get_loyalty_details(&self, company_id: String, vins: Vec<String>) -> thrift::Result<Vec<Box<LoyaltyEngagement>>>;
  fn handle_get_voluntary_protection_products(&self, company_id: String, promise_id: i32) -> thrift::Result<Vec<VoluntaryProtectionProduct>>;
  fn handle_get_voluntary_protection_products_link(&self, company_id: String, promise_id: i32) -> thrift::Result<VoluntaryProtectionProductLink>;
}

pub struct OEMServiceSyncProcessor<H: OEMServiceSyncHandler> {
  handler: H,
}

