pub trait MotorsServiceSyncHandler {
  fn handle_request_motors_years(&self) -> thrift::Result<Vec<BTreeMap<String, String>>>;
  fn handle_request_motors_makes(&self, year: String) -> thrift::Result<Vec<BTreeMap<String, String>>>;
  fn handle_request_motors_models(&self, vehicle: Vehicle) -> thrift::Result<Vec<BTreeMap<String, String>>>;
  fn handle_request_motors_trims(&self, vehicle: Vehicle) -> thrift::Result<Vec<BTreeMap<String, String>>>;
  fn handle_request_motors_vehicle_image(&self, vehicle: Vehicle) -> thrift::Result<String>;
  fn handle_request_motors_recommended_services(&self, vehicle: Vehicle) -> thrift::Result<Vec<RSServicePackage>>;
  fn handle_request_motors_vehicle_by_v_i_n(&self, vin: String) -> thrift::Result<Vec<Vehicle>>;
  fn handle_request_all_motors_make_models(&self) -> thrift::Result<Vec<MotorsModels>>;
}

pub struct MotorsServiceSyncProcessor<H: MotorsServiceSyncHandler> {
  handler: H,
}

