//
// TcpaService service processor
//

pub trait TcpaServiceSyncHandler {
  fn handle_get_replies(&self, user_id: i32, statuses: Vec<TcpaReplyStatus>, row_start: i32, rows_per_page: i32) -> thrift::Result<Vec<TcpaReply>>;
  fn handle_get_replies_count(&self, user_id: i32, statuses: Vec<TcpaReplyStatus>) -> thrift::Result<i32>;
  fn handle_mark_reviewed(&self, reply_id: i32) -> thrift::Result<()>;
  fn handle_reviewed_and_add(&self, reply_id: i32) -> thrift::Result<()>;
  fn handle_stop_and_add(&self, reply_id: i32) -> thrift::Result<()>;
  fn handle_insert_reply(&self, transcript_id: i32) -> thrift::Result<()>;
  fn handle_get_phrases(&self, types: Vec<TcpaPhraseType>, row_start: i32, rows_per_page: i32, search: String) -> thrift::Result<Vec<TcpaPhrase>>;
  fn handle_remove_phrase(&self, tcpa_phrase_id: i32) -> thrift::Result<()>;
  fn handle_add_phrase(&self, phrase_type: TcpaPhraseType, phrase: String) -> thrift::Result<i32>;
  fn handle_check_stop_phrase(&self, phrase: String) -> thrift::Result<bool>;
}

pub struct TcpaServiceSyncProcessor<H: TcpaServiceSyncHandler> {
  handler: H,
}

impl <H: TcpaServiceSyncHandler> TcpaServiceSyncProcessor<H> {
  pub fn new(handler: H) -> TcpaServiceSyncProcessor<H> {
    TcpaServiceSyncProcessor {
      handler,
    }
  }
  fn process_get_replies(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_get_replies(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_get_replies_count(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_get_replies_count(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_mark_reviewed(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_mark_reviewed(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_reviewed_and_add(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_reviewed_and_add(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_stop_and_add(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_stop_and_add(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_insert_reply(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_insert_reply(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_get_phrases(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_get_phrases(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_remove_phrase(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_remove_phrase(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_add_phrase(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_add_phrase(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_check_stop_phrase(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TTcpaServiceProcessFunctions::process_check_stop_phrase(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
}

