  fn sale(&mut self, payment_id: i32, amount: OrderedFloat<f64>, auth_request: PaymentAuthorizationRequest, signature: String, login_id: i32, params: BTreeMap<String, String>, department: PaymentDepartment) -> thrift::Result<PaymentResponse>;
