  fn terminal_sale(&mut self, payment_id: i32, amount: OrderedFloat<f64>, login_id: i32, params: BTreeMap<String, String>, department: PaymentDepartment) -> thrift::Result<PaymentResponse>;
  fn process_embedded_authorization(&mut self, payment_id: i32, processor_response: String, login_id: i32, department: PaymentDepartment) -> thrift::Result<PaymentResponse>;
  fn process_embedded_sale(&mut self, payment_id: i32, processor_response: String, login_id: i32, department: PaymentDepartment) -> thrift::Result<PaymentResponse>;
  fn cash_sale(&mut self, payment_id: i32, amount: OrderedFloat<f64>, login_id: i32, department: PaymentDepartment) -> thrift::Result<PaymentResponse>;
