//
// DocumentService service processor
//

pub trait DocumentServiceSyncHandler {
  fn handle_get_documents(&self, promise_id: i32) -> thrift::Result<Vec<Document>>;
  fn handle_get_document(&self, document_id: i32) -> thrift::Result<Document>;
  fn handle_sign_document(&self, document_id: i32, signature_areas: Vec<DocumentSignatureArea>, event: DocumentEvent) -> thrift::Result<PaymentResponse>;
  fn handle_get_document_data(&self, document_id: i32, signed: bool, event: DocumentEvent) -> thrift::Result<Vec<u8>>;
  fn handle_get_document_url(&self, document_id: i32, signed: bool, event: DocumentEvent) -> thrift::Result<String>;
  fn handle_log_document_event(&self, document_id: i32, event: DocumentEvent) -> thrift::Result<()>;
  fn handle_get_document_images(&self, document_id: i32) -> thrift::Result<Vec<DocumentImage>>;
  fn handle_save_signature_areas(&self, document_id: i32, signature_areas: Vec<DocumentSignatureArea>) -> thrift::Result<()>;
  fn handle_create_document(&self, promise_id: i32, filename: String, file_hash: String, signature_areas: Vec<DocumentSignatureArea>, page_hashes: Vec<String>, user_id: i32, issue_id: i32) -> thrift::Result<Document>;
  fn handle_delete_document(&self, document_id: i32) -> thrift::Result<bool>;
  fn handle_soft_delete_document(&self, document_id: i32) -> thrift::Result<bool>;
  fn handle_update_customer_approval(&self, promise_id: i32, approvals: Vec<IssueCustomerApproval>, message: String, from_tech: bool, ssf: OrderedFloat<f64>) -> thrift::Result<i32>;
  fn handle_update_approval_setting(&self, document_id: i32, needs_approval: bool, notes: String, price: OrderedFloat<f64>) -> thrift::Result<i32>;
  fn handle_get_unapproved(&self, promise_id: i32) -> thrift::Result<Vec<Issue>>;
  fn handle_get_approval(&self, approval_id: i32) -> thrift::Result<IssueApproval>;
  fn handle_get_approvals(&self, promise_id: i32) -> thrift::Result<Vec<ListIssueApproval>>;
  fn handle_upload(&self, data: Vec<u8>, key: String, filename: String) -> thrift::Result<String>;
  fn handle_import_ro_pdf(&self, promise_id: i32) -> thrift::Result<Document>;
  fn handle_get_video_url(&self, path: String) -> thrift::Result<String>;
  fn handle_get_asset_by_path(&self, path: String, bucket: String) -> thrift::Result<String>;
}

pub struct DocumentServiceSyncProcessor<H: DocumentServiceSyncHandler> {
  handler: H,
}

