pub trait MPIServiceSyncHandler {
  fn handle_get_issue(&self, issue_id: i32) -> thrift::Result<Issue>;
  fn handle_get_issues(&self, promise_id: i32) -> thrift::Result<Vec<Issue>>;
  fn handle_delete_issue(&self, issue_id: i32) -> thrift::Result<bool>;
  fn handle_update_issue(&self, issue_id: i32, service_id: i32, promise_id: i32, issue: String, correction: String, parts: String, parts_price: OrderedFloat<f64>, labor_price: OrderedFloat<f64>, labor_unit: OrderedFloat<f64>, op_code: String, notes: String, needs_approval: bool, key: String, parts_status: i32, parts_backorder_date: String, labor_type: String, severity: String, sort_order: i32, estimated_job_total: OrderedFloat<f64>, shop_supply_fee: OrderedFloat<f64>, send_to_estimate: bool, approval_method: String, approved: bool, discount: OrderedFloat<f64>, discount_type: String, is_dms_issue: bool, technician_id: i32, dispatch_code: String, est_duration: String, parts_person_id: i32, vehicle_service_id: i32) -> thrift::Result<i32>;
  fn handle_create_document(&self, issue_id: i32, filename: String, file_hash: String, user_id: i32) -> thrift::Result<Document>;
  fn handle_send(&self, promise_id: i32) -> thrift::Result<()>;
  fn handle_save(&self, promise_id: i32) -> thrift::Result<()>;
  fn handle_get_promise_id(&self, company_id: i32, unique_id: String) -> thrift::Result<i32>;
  fn handle_mark_viewed(&self, promise_id: i32) -> thrift::Result<()>;
  fn handle_get_form(&self, promise_id: i64) -> thrift::Result<String>;
  fn handle_get_parts_availability(&self, promise_id: i32, part_numbers: Vec<String>, part_sale_type: String) -> thrift::Result<()>;
  fn handle_update_technician(&self, promise_id: i32, login_id: i32) -> thrift::Result<bool>;
  fn handle_get_labor_levels_for_dealer(&self, company_id: i32) -> thrift::Result<Vec<ASGOLaborLevel>>;
  fn handle_set_default_labor_level(&self, labor_level_id: i32) -> thrift::Result<()>;
  fn handle_save_service_issue_labor_level(&self, promise_id: i32, service_issue_id: i32, labor_level_id: i32, item_type: i32) -> thrift::Result<i32>;
  fn handle_dealer_is_g_o(&self, company_id: i32) -> thrift::Result<bool>;
  fn handle_add_g_o_company(&self, company_id: i32, active: bool) -> thrift::Result<i32>;
  fn handle_set_company_inactive(&self, company_id: i32) -> thrift::Result<()>;
}

