impl <H: MPIServiceSyncHandler> TProcessor for MPIServiceSyncProcessor<H> {
  fn process(&self, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    let message_ident = i_prot.read_message_begin()?;
    let res = match &*message_ident.name {
      "getIssue" => {
        self.process_get_issue(message_ident.sequence_number, i_prot, o_prot)
      },
      "getIssues" => {
        self.process_get_issues(message_ident.sequence_number, i_prot, o_prot)
      },
      "deleteIssue" => {
        self.process_delete_issue(message_ident.sequence_number, i_prot, o_prot)
      },
      "updateIssue" => {
        self.process_update_issue(message_ident.sequence_number, i_prot, o_prot)
      },
      "createDocument" => {
        self.process_create_document(message_ident.sequence_number, i_prot, o_prot)
      },
      "send" => {
        self.process_send(message_ident.sequence_number, i_prot, o_prot)
      },
      "save" => {
        self.process_save(message_ident.sequence_number, i_prot, o_prot)
      },
      "getPromiseId" => {
        self.process_get_promise_id(message_ident.sequence_number, i_prot, o_prot)
      },
      "markViewed" => {
        self.process_mark_viewed(message_ident.sequence_number, i_prot, o_prot)
      },
      "getForm" => {
        self.process_get_form(message_ident.sequence_number, i_prot, o_prot)
      },
      "getPartsAvailability" => {
        self.process_get_parts_availability(message_ident.sequence_number, i_prot, o_prot)
      },
      "updateTechnician" => {
        self.process_update_technician(message_ident.sequence_number, i_prot, o_prot)
      },
      "getLaborLevelsForDealer" => {
        self.process_get_labor_levels_for_dealer(message_ident.sequence_number, i_prot, o_prot)
      },
      "setDefaultLaborLevel" => {
        self.process_set_default_labor_level(message_ident.sequence_number, i_prot, o_prot)
      },
      "saveServiceIssueLaborLevel" => {
        self.process_save_service_issue_labor_level(message_ident.sequence_number, i_prot, o_prot)
      },
      "dealerIsGO" => {
        self.process_dealer_is_g_o(message_ident.sequence_number, i_prot, o_prot)
      },
      "addGOCompany" => {
        self.process_add_g_o_company(message_ident.sequence_number, i_prot, o_prot)
      },
      "setCompanyInactive" => {
        self.process_set_company_inactive(message_ident.sequence_number, i_prot, o_prot)
      },
      method => {
        Err(
          thrift::Error::Application(
            ApplicationError::new(
              ApplicationErrorKind::UnknownMethod,
              format!("unknown method {}", method)
            )
          )
        )
      },
    };
    thrift::server::handle_process_result(&message_ident, res, o_prot)
  }
}

