impl <H: CampaignServiceSyncHandler> TProcessor for CampaignServiceSyncProcessor<H> {
  fn process(&self, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    let message_ident = i_prot.read_message_begin()?;
    let res = match &*message_ident.name {
      "submit" => {
        self.process_submit(message_ident.sequence_number, i_prot, o_prot)
      },
      "clearCustomerList" => {
        self.process_clear_customer_list(message_ident.sequence_number, i_prot, o_prot)
      },
      "addListCustomer" => {
        self.process_add_list_customer(message_ident.sequence_number, i_prot, o_prot)
      },
      "importList" => {
        self.process_import_list(message_ident.sequence_number, i_prot, o_prot)
      },
      "approve" => {
        self.process_approve(message_ident.sequence_number, i_prot, o_prot)
      },
      "save" => {
        self.process_save(message_ident.sequence_number, i_prot, o_prot)
      },
      "schedule" => {
        self.process_schedule(message_ident.sequence_number, i_prot, o_prot)
      },
      "cancel" => {
        self.process_cancel(message_ident.sequence_number, i_prot, o_prot)
      },
      "getById" => {
        self.process_get_by_id(message_ident.sequence_number, i_prot, o_prot)
      },
      "userAccess" => {
        self.process_user_access(message_ident.sequence_number, i_prot, o_prot)
      },
      "getCampaigns" => {
        self.process_get_campaigns(message_ident.sequence_number, i_prot, o_prot)
      },
      "getTemplates" => {
        self.process_get_templates(message_ident.sequence_number, i_prot, o_prot)
      },
      method => {
        Err(
          thrift::Error::Application(
            ApplicationError::new(
              ApplicationErrorKind::UnknownMethod,
              format!("unknown method {}", method)
            )
          )
        )
      },
    };
    thrift::server::handle_process_result(&message_ident, res, o_prot)
  }
}

