pub trait PrinterServiceSyncHandler {
  fn handle_update_printer(&self, printer_id: i32, company_id: i32, description: String, workorder_printer: String, parts_printer: String, workorder_copies: i32, sort_order: i32, default_printer: bool, active: bool, show: bool) -> thrift::Result<i32>;
  fn handle_get_printer(&self, printer_id: i32) -> thrift::Result<Printer>;
  fn handle_get_printers(&self, company_id: i32, active: bool) -> thrift::Result<Vec<Printer>>;
  fn handle_user_access(&self, printer_id: i32, user_id: i32) -> thrift::Result<bool>;
  fn handle_set_selected_printer(&self, user_id: i32, printer_id: i32) -> thrift::Result<()>;
  fn handle_get_selected_printer(&self, user_id: i32) -> thrift::Result<i32>;
}

pub struct PrinterServiceSyncProcessor<H: PrinterServiceSyncHandler> {
  handler: H,
}

impl <H: PrinterServiceSyncHandler> PrinterServiceSyncProcessor<H> {
  pub fn new(handler: H) -> PrinterServiceSyncProcessor<H> {
    PrinterServiceSyncProcessor {
      handler,
    }
  }
  fn process_update_printer(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TPrinterServiceProcessFunctions::process_update_printer(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_get_printer(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TPrinterServiceProcessFunctions::process_get_printer(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_get_printers(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TPrinterServiceProcessFunctions::process_get_printers(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_user_access(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TPrinterServiceProcessFunctions::process_user_access(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_set_selected_printer(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TPrinterServiceProcessFunctions::process_set_selected_printer(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
  fn process_get_selected_printer(&self, incoming_sequence_number: i32, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    TPrinterServiceProcessFunctions::process_get_selected_printer(&self.handler, incoming_sequence_number, i_prot, o_prot)
  }
}

