impl <H: MFAServiceSyncHandler> TProcessor for MFAServiceSyncProcessor<H> {
  fn process(&self, i_prot: &mut dyn TInputProtocol, o_prot: &mut dyn TOutputProtocol) -> thrift::Result<()> {
    let message_ident = i_prot.read_message_begin()?;
    let res = match &*message_ident.name {
      "sendToken" => {
        self.process_send_token(message_ident.sequence_number, i_prot, o_prot)
      },
      "verifyToken" => {
        self.process_verify_token(message_ident.sequence_number, i_prot, o_prot)
      },
      "rememberMe" => {
        self.process_remember_me(message_ident.sequence_number, i_prot, o_prot)
      },
      "disable" => {
        self.process_disable(message_ident.sequence_number, i_prot, o_prot)
      },
      "enable" => {
        self.process_enable(message_ident.sequence_number, i_prot, o_prot)
      },
      "reset" => {
        self.process_reset(message_ident.sequence_number, i_prot, o_prot)
      },
      "setPreferredMethod" => {
        self.process_set_preferred_method(message_ident.sequence_number, i_prot, o_prot)
      },
      "isEnabled" => {
        self.process_is_enabled(message_ident.sequence_number, i_prot, o_prot)
      },
      "getContact" => {
        self.process_get_contact(message_ident.sequence_number, i_prot, o_prot)
      },
      method => {
        Err(
          thrift::Error::Application(
            ApplicationError::new(
              ApplicationErrorKind::UnknownMethod,
              format!("unknown method {}", method)
            )
          )
        )
      },
    };
    thrift::server::handle_process_result(&message_ident, res, o_prot)
  }
}

